async function fetchGrafanaData(){try{console.log("Запрос данных из Grafana...");const fullUrl="/stats-proxy.php";console.log(`Запрос через локальный прокси: ${fullUrl}`);const response=await fetch(fullUrl);if(!response.ok){throw new Error(`HTTP error! status: ${response.status}`)}const data=await response.json();console.log("Реальные данные получены из Grafana:",data);return{athletes:data.athletes||1056}}catch(error){console.error("Ошибка получения данных через локальный прокси:",error);console.log("Используем последние известные данные");return{athletes:1056}}}async function updateStats(){const statsInfo=document.querySelector(".stats-info");if(statsInfo){statsInfo.style.opacity="0.7";statsInfo.textContent=`🏃‍♂️ Обновление данных...`}const grafanaData=await fetchGrafanaData();if(statsInfo){statsInfo.style.opacity="1";statsInfo.textContent=`${grafanaData.athletes} 🏃‍♂️ уже с нами`}console.log(`Статистика обновлена: ${grafanaData.athletes} атлетов в ${(new Date).toLocaleTimeString()}`)}const allTestimonials=[{quote:"Бот-тренер помог мне подготовиться к первому полумарафону. Индивидуальный план тренировок и постоянная поддержка - именно то, что нужно новичку. Результат 1:55 превзошел все ожидания!",author:"Анна Петрова"},{quote:"Цель была амбициозная - улучшить результаты на всех дистанциях одновременно. Бот составил идеальный план: 10км за 55 минут уже достиг, теперь иду к заветным 25 минутам на 5км. Спасибо за системный подход!",author:"Дмитрий Козлов"},{quote:"Отправляю боту скриншоты тренировок из приложения - он мгновенно анализирует данные и дает конкретные рекомендации. Прогрессивные тренировки стали намного эффективнее!",author:"Мария Сидорова"},{quote:"Удобно отправлять голосовые сообщения о тренировках - бот всё понимает и дает развернутые ответы. Обратная связь всегда конструктивная и мотивирующая!",author:"Алексей Иванов"},{quote:"Пробежала марафон 'Белые ночи' за 4:18 благодаря подготовке с ботом. Теперь цель - покорить рубеж 4 часов. Верю, что с таким тренером это реально!",author:"Елена Морозова"},{quote:"Фотографирую свои завтраки и обеды - бот считает КБЖУ и дает советы по питанию для бегунов. Это помогает поддерживать оптимальный вес и энергию для тренировок!",author:"Сергей Васильев"},{quote:"Мечтаю о мастере спорта по бегу! Текущие результаты: 10км за 54 минуты. Бот помогает планомерно идти к цели, учитывая мои физические данные и возможности. В 33 года всё только начинается!",author:"Ольга Романова"},{quote:"Разнообразие тренировок впечатляет: равномерный бег, фартлек, интервалы, повторы. Бот объясняет цель каждой тренировки и помогает выполнять их правильно. Прогресс очевиден!",author:"Игорь Соколов"},{quote:"Готовлюсь к марафону с целью 3:40-3:50. Бот учитывает даже погодные условия при анализе тренировок! 100-минутная пробежка в жару прошла под его контролем.",author:"Татьяна Волкова"},{quote:"Начал путь к марафону с большим лишним весом. Бот составил щадящий план, который постепенно готовит к большим нагрузкам. Уже чувствую прогресс и уверенность!",author:"Андрей Новиков"},{quote:"Все прошло хорошо. Выполнил все планы. Длительная прошла отлично, легко, без чувства усталости. Как и планировали по 5 мин на км, час двадцать. Средний пульс 147.",author:"Роман"},{quote:"Ты офигенный бот, спасибо! С тобой очень приятно общаться.",author:"Кристина"},{quote:"Неделя прошла хорошо. Пробежал что и предполагалось по задачам. В субботу сделал ОФП, а в воскресенье замкнул длительной 20 км, аэробно, средний темп 4:54.",author:"Роман"},{quote:"Отличный план, спасибо! Все понятно и структурированно.",author:"Дмитрий"},{quote:"Вчера я пробежала 14 км с набором высоты 330 метров в темпе 6:50. Самочувствие прекрасное!",author:"Мария"},{quote:"Ты очень сильно мне помогаешь. Чувствую себя отлично, всё по плану, достаточно легко контролирую нагрузки.",author:"Роман"}];function getRandomTestimonials(count=6){const shuffled=[...allTestimonials].sort(()=>.5-Math.random());return shuffled.slice(0,count)}function updateTestimonials(){const testimonialsGrid=document.querySelector(".testimonials-grid");if(!testimonialsGrid)return;const randomTestimonials=getRandomTestimonials(6);testimonialsGrid.style.opacity="0.3";setTimeout(()=>{testimonialsGrid.innerHTML=randomTestimonials.map(testimonial=>`
            <div class="testimonial-card">
                <div class="testimonial-quote">${testimonial.quote}</div>
                <div class="testimonial-author">— ${testimonial.author}</div>
            </div>
        `).join("");testimonialsGrid.style.opacity="1"},200)}const demoMessages=[{sender:"user",text:"Привет! Хочу начать бегать и подготовиться к забегу на 5 км. Я новичок в беге.",delay:1500},{sender:"bot",text:"Привет! Отлично, что решил заняться бегом — это классный выбор! Помогу тебе подготовиться к первому забегу на 5км максимально эффективно и безопасно.",delay:2500},{sender:"bot",text:"Давай познакомимся поближе для составления индивидуального плана:\n1. Сколько тебе лет, какой рост и вес?\n2. Есть ли какой-то спортивный опыт или физическая активность сейчас?\n3. Когда планируешь участвовать в забеге на 5км?",delay:2e3},{sender:"user",text:"Мне 28 лет, рост 175 см, вес 78 кг. Спортом особо не занимался последние годы, только иногда в спортзале.",delay:1800},{sender:"user",text:"Забег хочу пробежать через 2-3 месяца.",delay:1200},{sender:"bot",text:"Отлично! У нас достаточно времени для качественной подготовки — 8-12 недель это хороший срок для новичка. Твои параметры в норме, это плюс.",delay:2200},{sender:"bot",text:"Еще несколько важных вопросов:\n1. Сколько дней в неделю готов тренироваться?\n2. В какое время удобнее бегать — утром или вечером?\n3. Есть ли проблемы со здоровьем, травмы?\n4. Какую цель ставишь — просто финишировать или есть желаемое время?",delay:2e3},{sender:"user",text:"Могу тренироваться 3 раза в неделю, лучше вечером после работы. Здоровье в порядке, травм нет.",delay:1600},{sender:"user",text:"Хочу пробежать 5км за 30 минут или меньше — это реально для новичка?",delay:1400},{sender:"bot",text:"Цель пробежать 5км за 30 минут (темп 6:00/км) — абсолютно реальна для новичка за 2-3 месяца подготовки! Это хорошая мотивирующая цель.",delay:2800},{sender:"bot",text:"**План тренировок на неделю:**\n\n🏃‍♂️ **Понедельник** — Легкий бег 20-25 мин (пульс 120-140)\n🏃‍♂️ **Среда** — Интервальная тренировка: разминка 10 мин + 4х2 мин быстро/2 мин отдых + заминка 10 мин\n🏃‍♂️ **Пятница** — Длительный бег 30-40 мин в комфортном темпе",delay:3e3},{sender:"bot",text:"**Первые 2 недели:** можешь чередовать бег и быструю ходьбу\n**3-4 недели:** увеличиваем непрерывный бег\n**5-8 недели:** работаем над темпом и выносливостью",delay:2500},{sender:"bot",text:"Начнем уже на этой неделе? Готов к первой тренировке?",delay:1800}];let currentMessageIndex=0;let isPlaying=false;function createMessage(sender,text,animate=true){const messageDiv=document.createElement("div");messageDiv.className=`message ${sender}`;const avatarDiv=document.createElement("div");avatarDiv.className="message-avatar";if(sender==="bot"){const avatarImg=document.createElement("img");avatarImg.src="/generated-image.jpg";avatarImg.alt="Тренер";avatarImg.style.width="100%";avatarImg.style.height="100%";avatarImg.style.borderRadius="50%";avatarImg.style.objectFit="cover";avatarDiv.appendChild(avatarImg)}else{avatarDiv.textContent="👤"}const contentDiv=document.createElement("div");contentDiv.className="message-content";const formattedText=text.replace(/\n/g,"<br>").replace(/\*\*(.*?)\*\*/g,"<strong>$1</strong>");contentDiv.innerHTML=formattedText;const timeDiv=document.createElement("div");timeDiv.className="message-time";timeDiv.textContent=(new Date).toLocaleTimeString("ru-RU",{hour:"2-digit",minute:"2-digit"});contentDiv.appendChild(timeDiv);messageDiv.appendChild(avatarDiv);messageDiv.appendChild(contentDiv);if(animate){messageDiv.style.opacity="0";messageDiv.style.transform="translateY(30px) scale(0.95)"}return messageDiv}function createTypingIndicator(){const typingDiv=document.createElement("div");typingDiv.className="message bot typing";const avatarDiv=document.createElement("div");avatarDiv.className="message-avatar";const avatarImg=document.createElement("img");avatarImg.src="/generated-image.jpg";avatarImg.alt="Тренер";avatarImg.style.width="100%";avatarImg.style.height="100%";avatarImg.style.borderRadius="50%";avatarImg.style.objectFit="cover";avatarDiv.appendChild(avatarImg);const typingIndicator=document.createElement("div");typingIndicator.className="typing-indicator";typingIndicator.innerHTML=`
        <div class="typing-dots">
            <div class="typing-dot"></div>
            <div class="typing-dot"></div>
            <div class="typing-dot"></div>
        </div>
    `;typingDiv.appendChild(avatarDiv);typingDiv.appendChild(typingIndicator);return typingDiv}function showMessage(messageElement,delay=0){return new Promise(resolve=>{setTimeout(()=>{messageElement.style.opacity="1";messageElement.style.transform="translateY(0) scale(1)";messageElement.style.transition="all 0.8s cubic-bezier(0.23, 1, 0.32, 1)";const chatMessages=document.getElementById("chat-messages");const messages=Array.from(chatMessages.children);messages.forEach((msg,index)=>{if(index<messages.length-3){msg.style.transform=`translateY(-${(messages.length-index-3)*8}px) scale(${1-(messages.length-index-3)*.05})`;msg.style.opacity=`${Math.max(.3,1-(messages.length-index-3)*.2)}`;msg.style.zIndex=index}else{msg.style.transform="translateY(0) scale(1)";msg.style.opacity="1";msg.style.zIndex=10+index}});if(messages.length>8){const oldestMessage=messages[0];oldestMessage.style.animation="messageDisappear 0.6s cubic-bezier(0.68, -0.55, 0.265, 1.55)";oldestMessage.style.animationFillMode="forwards";setTimeout(()=>{if(oldestMessage.parentNode){oldestMessage.parentNode.removeChild(oldestMessage)}},600)}resolve()},delay)})}async function playNextMessage(){if(currentMessageIndex>=demoMessages.length){isPlaying=false;setTimeout(()=>{startDemo()},5e3);return}const chatMessages=document.getElementById("chat-messages");const message=demoMessages[currentMessageIndex];let typingIndicator=null;if(message.sender==="bot"){typingIndicator=createTypingIndicator();chatMessages.appendChild(typingIndicator);chatMessages.scrollTop=chatMessages.scrollHeight;await new Promise(resolve=>setTimeout(resolve,1500));chatMessages.removeChild(typingIndicator)}const messageElement=createMessage(message.sender,message.text);chatMessages.appendChild(messageElement);await showMessage(messageElement,100);currentMessageIndex++;setTimeout(()=>{if(isPlaying){playNextMessage()}},message.delay)}function startDemo(){const chatMessages=document.getElementById("chat-messages");isPlaying=true;currentMessageIndex=0;chatMessages.innerHTML="";setTimeout(()=>{playNextMessage()},1e3)}function restartDemo(){setTimeout(()=>{if(!isPlaying){startDemo()}},5e3)}function detectLanguageAndRedirect(){if(window.location.pathname==="/en/"||window.location.pathname.includes("index-en")){return}const savedLanguage=localStorage.getItem("preferredLanguage");if(savedLanguage==="en"){window.location.href="/en/";return}if(savedLanguage){return}const browserLanguage=navigator.language||navigator.languages[0];if(browserLanguage.startsWith("en")){localStorage.setItem("preferredLanguage","en");window.location.href="/en/"}else{localStorage.setItem("preferredLanguage","ru")}}function setupLanguageSwitchers(){const languageLinks=document.querySelectorAll(".language-switch a");languageLinks.forEach(link=>{link.addEventListener("click",function(e){e.preventDefault();const href=this.getAttribute("href");const language=href==="/en/"?"en":"ru";localStorage.setItem("preferredLanguage",language);window.location.href=href})})}document.addEventListener("DOMContentLoaded",function(){if(window.location.pathname==="/"||window.location.pathname==="/index.html"){detectLanguageAndRedirect()}setupLanguageSwitchers();updateStats();updateTestimonials();setTimeout(()=>{startDemo()},2e3)});setInterval(updateStats,12e4);setInterval(updateTestimonials,1e4);